/**
 * TravelWell.World — Local & temporal signals (the "knows what's happening"
 * layer behind Atlas + Well Whispers).
 *
 * Authoring pattern mirrors safety-data.ts: a typed, framework-free module.
 * Curated "Tier A" entries are the offline-first fallback and the seed for the
 * public.local_signals table (migration 0007, generated by
 * scripts/gen-catalog-seed.ts) — served from Postgres, editable without a
 * redeploy, authored in the repo with review.
 *
 * Honesty contract (mirrors safety-data + Atlas's own rules): never fabricate a
 * dated "happening now." Curate things genuinely true and stable — recurring
 * seasons/schedules and well-known annual moments. Volatile "tonight" data is
 * Tier C (provider-fed), not authored here. Every entry keeps a `source`.
 *
 * CONTENT: David authors batches (in the LocalSignal shape) and Sana drops them
 * in here, normalizing SI tags to real keys + mapping regions. `destination` is
 * a free-text place key (NOT constrained to the destinations catalog), so
 * signals can name places we don't model yet.
 *
 * Keyed by destination and/or region, tagged by Special Interest and Well so
 * Atlas and the cross-link engine find what's relevant.
 */

export type SignalKind = "event" | "schedule" | "opening" | "lookahead";
export type SignalHorizon = "now" | "soon" | "lookahead";

export interface LocalSignal {
  id: string;
  kind: SignalKind;
  horizon: SignalHorizon;
  title: string;
  blurb?: string;            // the gentle line, in Atlas's voice
  href?: string;             // real one-tap link (internal guide or external)
  destination?: string;      // free-text place key (e.g. "raja-ampat")
  region?: string;           // regions.code
  si?: string[];             // relevant Special Interests (real taxonomy keys)
  wells?: string[];          // cross-link engine targets
  season?: string;           // human label, e.g. "Jul–Oct"
  recurrence?: { months?: number[]; days?: number[] }; // months 1-12, days 0-6 (Sun=0)
  startsOn?: string;         // ISO — for genuinely dated events
  endsOn?: string;           // ISO
  validFrom?: string;        // ISO — when to start surfacing
  validTo?: string;          // ISO
  priority?: number;
  source: "curated" | "feed" | "provider";
  // Structured extras for TLEU look-ahead events (ticket_drop / book_by /
  // sells_out / high_intent / upsell_ladder, …). Free-form so the event map
  // ingests without new columns per field.
  meta?: Record<string, unknown>;
}

