/** True when a signal's recurring window includes the given month (1-12). */
export function isActiveInMonth(s: LocalSignal, month: number): boolean {
  if (s.recurrence?.months?.length) return s.recurrence.months.includes(month);
  if (s.startsOn && s.endsOn) {
    const a = new Date(s.startsOn).getMonth() + 1;
    const b = new Date(s.endsOn).getMonth() + 1;
    return a <= b ? month >= a && month <= b : month >= a || month <= b;
  }
  return true; // no temporal bound → always relevant
}

/**
 * Pure relevance filter usable on the bundle or DB rows. A signal is relevant if
 * it matches the traveler's place (destination/region), OR overlaps their chosen
 * Special Interests (so dive-season signals surface for a diver even before they
 * land on a specific destination page), OR is global. Ranked: place-matches
 * first, then in-season, then priority.
 */
export function selectSignals(
  all: LocalSignal[],
  q: { destination?: string | null; region?: string | null; si?: string[]; month?: number }
): LocalSignal[] {
  const wantSi = q.si?.length ? new Set(q.si) : null;
  const scored = all
    .map((s) => {
      const placeMatch =
        (!!q.destination && s.destination === q.destination) || (!!q.region && s.region === q.region);
      const siMatch = !!wantSi && !!s.si?.some((x) => wantSi.has(x));
      const global = !s.destination && !s.region;
      return { s, placeMatch, keep: placeMatch || siMatch || global };
    })
    .filter((x) => x.keep);
  return scored
    .sort((a, b) => {
      if (a.placeMatch !== b.placeMatch) return a.placeMatch ? -1 : 1;
      if (q.month != null) {
        const ai = isActiveInMonth(a.s, q.month) ? 1 : 0;
        const bi = isActiveInMonth(b.s, q.month) ? 1 : 0;
        if (ai !== bi) return bi - ai;
      }
      return (b.s.priority ?? 0) - (a.s.priority ?? 0);
    })
    .map((x) => x.s);
}
